// Formato Contaplus (ASC) 
// Longitud fija por campo
const facturas = $('Leer Facturas PostgreSQL').all().map(i => i.json);
const body = $('Webhook').first().json.body || {};
const ejercicio = body.ejercicio || new Date().getFullYear().toString().substring(2);

const lineas = [];
let numAsiento = 1;

function pad(str, len, char=' ') { return String(str || '').substring(0,len).padEnd(len, char); }
function padNum(num, len) { return Number(num || 0).toFixed(2).padStart(len, ' '); }

for (const f of facturas) {
  const fecha = (f.fecha_factura || '').split('-').reverse().join(''); // DDMMYYYY
  const esCompra = (f.tipo_documento || 'compra') !== 'venta';
  const base = Number(f.base_imponible) || Number(f.total_factura) || 0;
  const iva = Number(f.cuota_iva) || 0;
  const total = Number(f.total_factura) || 0;
  const cuenta = (f.cuenta_gasto || '629').padEnd(10, '0');
  const concepto = pad(f.nombre_emisor || '', 25);
  const nif = pad(f.nif_emisor || '', 15);
  const numFra = pad(f.numero_factura || '', 15);
  const asiento = String(numAsiento).padStart(8, '0');

  if (esCompra) {
    // Gasto al Debe
    lineas.push(ejercicio + asiento + fecha + cuenta + padNum(base,14) + padNum(0,14) + concepto + nif + 'D' + numFra);
    // IVA al Debe
    if (iva > 0) {
      lineas.push(ejercicio + asiento + fecha + '4720000000' + padNum(iva,14) + padNum(0,14) + pad('IVA SOPORTADO',25) + nif + 'D' + numFra);
    }
    // Proveedor al Haber
    lineas.push(ejercicio + asiento + fecha + '4000000001' + padNum(0,14) + padNum(total,14) + concepto + nif + 'H' + numFra);
  } else {
    // Cliente al Debe
    lineas.push(ejercicio + asiento + fecha + '4300000001' + padNum(total,14) + padNum(0,14) + concepto + nif + 'D' + numFra);
    // Ingreso al Haber
    lineas.push(ejercicio + asiento + fecha + cuenta + padNum(0,14) + padNum(base,14) + concepto + nif + 'H' + numFra);
    if (iva > 0) {
      lineas.push(ejercicio + asiento + fecha + '4770000000' + padNum(0,14) + padNum(iva,14) + pad('IVA REPERCUTIDO',25) + nif + 'H' + numFra);
    }
  }
  numAsiento++;
}

return [{
  json: {
    success: true,
    total_facturas: facturas.length,
    formato: 'Contaplus',
    csv_content: lineas.join('\n'),
    filename: 'kontia_contaplus_' + new Date().toISOString().split('T')[0] + '.asc'
  }
}];
